INSERT INTO terms (id, term, term_ja, chapter_id, order_index, difficulty, one_liner, definition, mechanism, analogy, pitfall, related_terms, story_context)
VALUES
  ('url', 'URL', 'ユーアールエル', 6, 1, 1, 'インターネット上の住所', 'Uniform Resource Locatorの略。インターネット上のリソース（Webページ、画像など）の場所を示す文字列。', 'プロトコル://ドメイン:ポート/パス?クエリ#フラグメント の構造を持つ。例：https://www.example.com:443/path?name=test#section', '家の住所。「東京都渋谷区〇〇町1-2-3」のように、目的地を一意に特定できる文字列。', 'URLとURIは厳密には異なる（URIの方が広い概念）が、実務ではほぼ同じ意味で使われる。', ARRAY['domain', 'path-parameter', 'query-string'], '港に到着。船長が地図を広げて「まず、URL を教えよう」と説明を始める。'),
  ('link', 'Link', 'リンク', 6, 2, 1, 'ページとページをつなぐ橋', 'あるWebページから別のページやリソースへの参照。クリックすると別の場所に移動できる。', 'HTMLの <a> タグで作成。href 属性に移動先のURLを指定する。テキストや画像をリンクにできる。', 'ドアや扉。クリックすると別の部屋（ページ）に移動できる入り口。', 'リンク切れ（404エラー）に注意。リンク先が削除・移動されると機能しなくなる。', ARRAY['hyperlink', 'anchor-tag', 'href'], '「Link は、ページとページをつなぐ橋だ」'),
  ('hyperlink', 'Hyperlink', 'ハイパーリンク', 6, 3, 1, 'クリックで別のページに飛べる仕組み', 'ハイパーテキストにおける、文書間を結ぶリンク。クリックすると別のドキュメントやリソースに移動できる。', 'Webの基本的な仕組み。HTMLの誕生時からある機能で、World Wide Web の「Web（網）」の由来。', 'ワープゾーン。クリックするだけで、世界中のどこへでも一瞬で移動できる魔法の扉。', 'Link と Hyperlink はほぼ同じ意味で使われる。Hyperlink の方がより正式な用語。', ARRAY['link', 'anchor-tag', 'url'], '「Hyperlink とも呼ぶ。クリックすると別のページに飛べる」'),
  ('anchor-tag', 'Anchor tag', 'アンカータグ', 6, 4, 1, 'リンクを作るHTMLタグ', 'HTMLでハイパーリンクを作成するための <a> タグ。anchor（錨）の「a」。', '<a href="https://example.com">リンクテキスト</a> の形で使用。target="_blank" で新しいタブで開く。', '船の錨（いかり）。ある場所（URL）に「固定」して、そこへの道標を作る。', 'target="_blank" を使う場合は、セキュリティ対策として rel="noopener noreferrer" を追加する。', ARRAY['href', 'link', 'html'], '「HTML では Anchor tag <a> を使って作る」'),
  ('href', 'Href', 'エイチレフ', 6, 5, 1, 'リンク先を指定する属性', 'Hypertext Reference の略。<a> タグや <link> タグで、参照先のURLを指定する属性。', '<a href="https://example.com">リンク</a> のように使用。相対パスや絶対パスで指定できる。', '行き先を書いた看板。「東京駅はこちら→」のように、どこに行くかを示す。', 'href を空にしたり # だけにすると、ページトップに戻る動作になる。意図しない場合は注意。', ARRAY['anchor-tag', 'url', 'link'], '「Href 属性に、飛び先の URL を指定するんだ」'),
  ('path-parameter', 'Path parameter', 'パスパラメータ', 6, 6, 2, 'URLのパス部分に含める値', 'URLのパス部分に埋め込まれる動的な値。特定のリソースを識別するために使用される。', '/users/123 の 123 がパスパラメータ。APIでは /users/:id のように : で定義することが多い。', 'マンションの部屋番号。「〇〇マンション/301号室」の301がパスパラメータ。', 'パスパラメータとクエリパラメータの使い分け。リソースの識別にはパス、フィルタや検索にはクエリを使う。', ARRAY['url', 'query-parameter', 'route'], '「Path parameter は /users/123 のように、URL のパスに含める値」'),
  ('query-string', 'Query string', 'クエリ文字列', 6, 7, 2, 'URLの?以降に追加する情報', 'URLの末尾に ? で始まり、key=value 形式で追加されるパラメータ群。複数ある場合は & で連結。', '?name=test&age=20 のような形式。検索条件やフィルタ、ページ番号などを渡すのに使用。', '注文時のオプション指定。「ラーメン？麺固め&ネギ多め」のように、追加の条件を伝える。', '機密情報をクエリ文字列に含めない。URLはログに残りやすく、他人に見られる可能性がある。', ARRAY['query-parameter', 'url', 'get'], '「Query string は ? 以降に追加する情報」'),
  ('query-parameter', 'Query parameter', 'クエリパラメータ', 6, 8, 2, 'クエリ文字列内の1つのkey=value', 'クエリ文字列内の個々のパラメータ。name=test のような key=value のペア1つ分を指す。', '?name=test&age=20 なら、name=test と age=20 がそれぞれクエリパラメータ。', '注文書の1項目。「名前：山田」「年齢：20」のそれぞれがクエリパラメータ。', '値に特殊文字（&、=、スペースなど）を含む場合はURLエンコードが必要。', ARRAY['query-string', 'url', 'path-parameter'], '「その中の name=test のようなひとつひとつのペアのことだ」'),
  ('domain', 'Domain', 'ドメイン', 6, 9, 1, 'インターネット上の名前（住所の名前部分）', 'example.com のような、インターネット上のコンピュータを識別する人間が読みやすい名前。', 'IPアドレス（数字の羅列）に対応する覚えやすい名前。DNSで実際のIPアドレスに変換される。', '店の名前。「〇〇商店」という名前で呼べば、住所を覚えていなくても場所がわかる。', 'ドメインは購入・管理が必要。期限切れになると他人に取得されることも。', ARRAY['subdomain', 'dns', 'ip-address'], '「Domain は example.com のような、覚えやすい名前」'),
  ('subdomain', 'Subdomain', 'サブドメイン', 6, 10, 2, 'ドメインの前につく補助的な名前', 'メインドメインの前に付けて、サイトを分類・区別するための名前。www、blog、api などがよく使われる。', 'blog.example.com の blog がサブドメイン。1つのドメインで複数のサービスを運用できる。', '部署名。「〇〇会社 営業部」「〇〇会社 開発部」のように、同じ会社内の区分け。', 'www はサブドメインの一種。www.example.com と example.com は厳密には別のアドレス。', ARRAY['domain', 'dns', 'url'], '「Subdomain は www のような、ドメインの前につく部分」'),
  ('dns', 'DNS', 'ディーエヌエス', 6, 11, 2, 'ドメイン名をIPアドレスに変換する仕組み', 'Domain Name System の略。人間が読みやすいドメイン名を、コンピュータが理解できるIPアドレスに変換するシステム。', 'ブラウザでURLを入力すると、DNSサーバーに問い合わせてIPアドレスを取得し、そのサーバーに接続する。', '電話帳。名前（ドメイン）で検索すると、電話番号（IPアドレス）がわかる。', 'DNSの設定変更は反映に時間がかかる（数時間〜48時間）。TTL（キャッシュ時間）の概念を理解しておく。', ARRAY['domain', 'ip-address', 'server'], '「DNS は、ドメイン名を IP アドレスに変換する電話帳のようなものだ」'),
  ('ip-address', 'IP address', 'アイピーアドレス', 6, 12, 2, 'コンピュータの数字の住所', 'Internet Protocol address の略。ネットワーク上のコンピュータを識別する数字の羅列。', 'IPv4は 192.168.1.1 のような形式（32ビット）、IPv6は 2001:0db8:... のような形式（128ビット）。', '電話番号。数字の並びだけで、世界中のどのコンピュータかを特定できる。', 'プライベートIPとグローバルIPの違いを理解する。家庭内LANのIPは外部からは見えない。', ARRAY['dns', 'domain', 'server'], '「実際のコンピュータは IP address という数字の住所を持っている」'),
  ('port', 'Port', 'ポート', 6, 13, 2, '通信の窓口番号', '1台のコンピュータ上で複数のサービスを区別するための番号（0〜65535）。', 'HTTP は 80番、HTTPS は 443番、開発サーバーは 3000番や 8080番がよく使われる。', 'マンションの部屋番号。住所（IPアドレス）が同じでも、部屋番号（ポート）で届け先を区別。', 'ウェルノウンポート（0-1023）は特別な権限が必要。開発時は1024以上を使うことが多い。', ARRAY['ip-address', 'http', 'https'], '「Port は、通信の『窓口番号』のようなもの。HTTP は 80番、HTTPS は 443番を使う」'),
  ('http', 'HTTP', 'エイチティーティーピー', 6, 14, 1, 'Webページを取得するための通信ルール', 'HyperText Transfer Protocol の略。WebブラウザとWebサーバー間でデータをやり取りするための通信プロトコル。', 'クライアントがリクエストを送り、サーバーがレスポンスを返す。GET、POST などのメソッドがある。', '手紙のやり取りのルール。「宛名はここ」「切手はここ」のような、通信の決まりごと。', 'HTTP は暗号化されていない。パスワードなど機密情報を扱う場合は HTTPS を使う。', ARRAY['https', 'request', 'response'], '「HTTP は、Web ページを取得するためのルールだ」'),
  ('https', 'HTTPS', 'エイチティーティーピーエス', 6, 15, 1, '暗号化されたHTTP', 'HTTP Secure の略。HTTPに暗号化（SSL/TLS）を追加したプロトコル。通信内容が第三者に読まれない。', 'SSL/TLS証明書でサーバーの身元を確認し、通信を暗号化。URLは https:// で始まる。', '封書。はがき（HTTP）は誰でも読めるが、封書（HTTPS）は開けないと中身が見えない。', 'HTTPSでも100%安全ではない。フィッシングサイトがHTTPS対応していることもある。', ARRAY['http', 'ssl-tls', 'security'], '「HTTPS は、HTTP に暗号化を加えたもの。南京錠マークが出ていれば安全に通信している証拠だ」'),
  ('ssl-tls', 'SSL/TLS', 'エスエスエル・ティーエルエス', 6, 16, 2, '通信を暗号化する技術', 'Secure Sockets Layer / Transport Layer Security の略。インターネット通信を暗号化するセキュリティ技術。', '公開鍵暗号を使って通信を暗号化。証明書でサーバーの身元を証明し、中間者攻撃を防ぐ。', '特殊なインクと専用メガネ。特殊インク（暗号化）で書いた手紙は、専用メガネ（復号キー）がないと読めない。', 'SSLは古く脆弱性があるため、現在はTLSが使われる。ただし慣習的に「SSL証明書」と呼ばれることが多い。', ARRAY['https', 'encryption', 'certificate'], '「SSL/TLS という技術で安全に通信する」'),
  ('protocol', 'Protocol', 'プロトコル', 6, 17, 1, '通信のルール・約束事', 'コンピュータ同士が通信するための取り決め・ルール。HTTP、HTTPS、FTP、SMTPなど様々な種類がある。', 'データの形式、送受信の手順、エラー処理などを規定。両者が同じプロトコルに従うことで通信が成立。', '言語やマナー。日本語話者同士なら日本語で、英語話者同士なら英語で会話するような約束事。', '用途に応じて適切なプロトコルを選ぶ。Web は HTTP/HTTPS、メールは SMTP/POP3/IMAP など。', ARRAY['http', 'https', 'tcp-ip'], '「船が港に入るとき、決まったルールがあるように、インターネットにも Protocol がある」'),
  ('request', 'Request', 'リクエスト', 6, 18, 1, 'サーバーへの「お願い」', 'クライアント（ブラウザなど）からサーバーに送る要求。「このページをください」「このデータを保存して」などの依頼。', 'HTTPメソッド（GET、POSTなど）、URL、ヘッダー、ボディで構成。サーバーはこれを受けてレスポンスを返す。', 'レストランでの注文。「カレーください」とお願い（リクエスト）すると、料理（レスポンス）が来る。', 'リクエストには適切なメソッドを使う。データ取得は GET、作成は POST、更新は PUT、削除は DELETE。', ARRAY['response', 'http', 'get'], '「通信は Request と Response のやり取りで成り立っている」'),
  ('response', 'Response', 'レスポンス', 6, 19, 1, 'サーバーからの「返事」', 'サーバーがクライアントのリクエストに対して返す応答。ステータスコード、ヘッダー、ボディ（データ本体）で構成。', 'リクエストを処理した結果を返す。成功なら200系、エラーなら400系や500系のステータスコードと共に返却。', '注文に対する料理の提供。お願いに対して「はい、どうぞ」と結果を返す。', 'レスポンスが遅いとユーザー体験が悪化する。パフォーマンス最適化の重要性を理解する。', ARRAY['request', 'status-code', 'http'], '「ブラウザがサーバーに『お願い』を送り、サーバーが『返事』を返す。この繰り返しで Web は動いている」'),
  ('status-code', 'Status code', 'ステータスコード', 6, 20, 1, 'サーバーの返事の結果を示す3桁の数字', 'HTTPレスポンスに含まれる3桁の数字。リクエストが成功したか、エラーかなどの状態を示す。', '1xx（情報）、2xx（成功）、3xx（リダイレクト）、4xx（クライアントエラー）、5xx（サーバーエラー）に分類。', 'テストの点数や成績表。「100点（成功）」「0点（エラー）」のように、結果を数字で表す。', 'エラーコードの意味を理解しておく。404は「見つからない」、500は「サーバー内部エラー」など。', ARRAY['200-ok', '404-not-found', '500-internal-server-error'], '「サーバーからの返事には Status code がつく」'),
  ('200-ok', '200 OK', '200 オーケー', 6, 21, 1, '成功！問題なし', 'リクエストが正常に処理されたことを示すHTTPステータスコード。最も基本的な成功レスポンス。', 'GET なら要求したデータが返され、POST なら処理が完了したことを意味する。', '「了解しました！」という返事。注文通りに料理が出てきた状態。', '200でも中身が期待通りとは限らない。レスポンスボディの内容も確認する習慣をつける。', ARRAY['status-code', 'response', '201-created'], '「200 OK は『成功！問題なし』」'),
  ('400-bad-request', '400 Bad Request', '400 バッドリクエスト', 6, 22, 1, 'リクエストの仕方が間違っている', 'クライアント側のリクエストに問題があることを示すステータスコード。構文エラーや不正なパラメータなど。', '必須パラメータの欠落、不正な JSON 形式、値の形式エラーなどで発生。', '「注文の仕方が間違っています」。メニューにない料理を注文したり、注文の言い方が理解できない状態。', '400エラーが出たらリクエストの内容を確認。APIドキュメントと照らし合わせる。', ARRAY['status-code', 'request', 'validation'], '「400 Bad Request は『お願いの仕方が間違っている』」'),
  ('401-unauthorized', '401 Unauthorized', '401 アンオーソライズド', 6, 23, 1, '認証が必要です', 'リクエストに認証情報が必要だが、提供されていないか無効であることを示すステータスコード。', 'ログインしていない、トークンが期限切れ、認証情報が間違っているなどで発生。', '「会員証を見せてください」。入場にはチケット（認証）が必要だが、持っていない状態。', '401と403の違い：401は「誰だかわからない（認証なし）」、403は「誰かはわかるがダメ（権限なし）」。', ARRAY['status-code', 'authentication', '403-forbidden'], '「401 Unauthorized は『ログインが必要です』」'),
  ('403-forbidden', '403 Forbidden', '403 フォービドゥン', 6, 24, 1, 'アクセス権限がありません', '認証はされているが、そのリソースへのアクセス権限がないことを示すステータスコード。', '管理者専用ページに一般ユーザーがアクセスしようとした場合などに発生。', '「関係者以外立入禁止」。身分証（認証）はあるが、そのエリアに入る権限がない状態。', '403が出たら権限の確認を。必要なロール（役割）が割り当てられているかチェック。', ARRAY['status-code', 'authorization', '401-unauthorized'], '「403 Forbidden は『アクセス権限がありません』」'),
  ('404-not-found', '404 Not Found', '404 ノットファウンド', 6, 25, 1, 'お探しのページは見つかりません', '指定されたURLのリソースが存在しないことを示すステータスコード。最も有名なエラーコード。', 'URLのタイプミス、ページの削除・移動、リンク切れなどで発生。', '「その住所には何もありません」。引っ越した後の家、または存在しない住所を訪ねた状態。', '404ページはカスタマイズできる。ユーザーフレンドリーな404ページを用意すると親切。', ARRAY['status-code', 'url', 'routing'], '「404 Not Found は『お探しのページは見つかりません』」'),
  ('500-internal-server-error', '500 Internal Server Error', '500 インターナルサーバーエラー', 6, 26, 1, 'サーバー側で問題が起きた', 'サーバー内部で予期しないエラーが発生したことを示すステータスコード。サーバー側の問題。', 'プログラムのバグ、データベース接続エラー、設定ミスなど、サーバー側の様々な原因で発生。', '「厨房で事故が起きました」。注文は正しいのに、キッチン（サーバー）側の問題で料理が出せない。', '500エラーはユーザーのせいではない。開発者はサーバーログを確認して原因を特定する。', ARRAY['status-code', 'server', 'error'], '「500 Internal Server Error は『サーバー側で問題が起きた』」'),
  ('rss', 'RSS', 'アールエスエス', 6, 27, 2, 'サイトの更新情報を配信する仕組み', 'Really Simple Syndication の略。ブログやニュースサイトの更新情報を配信するためのXML形式のフォーマット。', 'RSSリーダーがRSSフィードを定期的に取得し、新着記事をまとめて表示。複数サイトの更新を一括管理。', '新聞の定期購読。わざわざ各サイトを見に行かなくても、更新情報が届く仕組み。', 'SNSの普及でRSSの利用は減少したが、技術ブログなどでは今でも活用されている。', ARRAY['xml', 'feed', 'blog'], '「RSS は、ブログの更新情報を配信する仕組みだ。好きなサイトの新着をまとめてチェックできる」'),
  ('smtp', 'SMTP', 'エスエムティーピー', 6, 28, 2, 'メールを送るためのプロトコル', 'Simple Mail Transfer Protocol の略。電子メールを送信するための通信プロトコル。', 'メールクライアントからメールサーバーへ、またはサーバー間でメールを転送する際に使用。受信はPOP3やIMAPを使用。', '郵便配達の仕組み。手紙（メール）を郵便局（サーバー）に届けるルール。受け取りは別の仕組み。', 'SMTPは送信専用。受信にはPOP3（ダウンロード型）やIMAP（同期型）を使う。', ARRAY['protocol', 'email', 'server'], '「SMTP は、メールを送るためのプロトコルだ」'),
  ('egress', 'Egress', 'イーグレス', 6, 29, 2, '外向きの通信（出ていくデータ）', 'ネットワークから外部へ出ていく通信やデータの流れ。サーバーからクライアントへの送信など。', 'クラウドサービスでは egress（送信）に課金されることが多い。ファイアウォールで制御することも。', '建物の出口。中から外へ出る（データが出ていく）方向。', 'クラウドの料金体系では egress 料金に注意。大量のデータを送信すると高額になることも。', ARRAY['ingress', 'traffic', 'bandwidth'], '「Egress は出ていく通信のことだ」'),
  ('ingress', 'Ingress', 'イングレス', 6, 30, 2, '内向きの通信（入ってくるデータ）', '外部からネットワーク内部へ入ってくる通信やデータの流れ。クライアントからサーバーへのリクエストなど。', 'Kubernetesの Ingress リソースは、外部からクラスタ内サービスへのアクセスを制御する。', '建物の入口。外から中へ入る（データが入ってくる）方向。', 'Kubernetes の「Ingress」は固有名詞として使われることも多い。文脈で判断する。', ARRAY['egress', 'traffic', 'kubernetes'], '「Ingress は入ってくる通信、Egress は出ていく通信のことだ」')
